@page "/apply"
@rendermode InteractiveServer

@using sv_e79b6c62dd1745f3a1c107394483f632.Components.Pages.Apply
@using sv_e79b6c62dd1745f3a1c107394483f632.Models
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4 text-center">Job Application</h2>

    <StepIndicator CurrentStep="currentStep" OnNavigateToStep="GoToStep" />

    @switch (currentStep)
    {
        case 0:
            <PersonalInfoStep
                @bind-FullName="fullName"
                @bind-Email="email"
                @bind-Phone="phone"
                @bind-Address="address"
                ValidateEmail="ApplicationService.ValidateEmailAsync"
                OnNext="NextStep" />
            break;

        case 1:
            <WorkHistoryStep
                @bind-Entries="workEntries"
                OnNext="NextStep"
                OnBack="PreviousStep" />
            break;

        case 2:
            <ReferencesStep
                @bind-References="references"
                OnNext="NextStep"
                OnBack="PreviousStep" />
            break;

        case 3:
            <CoverLetterStep
                @bind-CoverLetter="coverLetter"
                OnNext="NextStep"
                OnBack="PreviousStep" />
            break;

        case 4:
            <ReviewStep
                FullName="@fullName"
                Email="@email"
                Phone="@phone"
                Address="@address"
                WorkEntries="workEntries"
                References="references"
                CoverLetter="@coverLetter"
                OnBack="PreviousStep"
                OnEditSection="GoToStep"
                SubmitApplication="HandleSubmit" />
            break;
    }
</div>

@code {
    private int currentStep = 0;

    // Step 1: Personal Info
    private string fullName = "";
    private string email = "";
    private string phone = "";
    private string address = "";

    // Step 2: Work History
    private List<WorkHistoryStep.WorkEntryModel> workEntries = new()
    {
        new WorkHistoryStep.WorkEntryModel()
    };

    // Step 3: References
    private List<ReferencesStep.ReferenceModel> references = new()
    {
        new ReferencesStep.ReferenceModel(),
        new ReferencesStep.ReferenceModel()
    };

    // Step 4: Cover Letter
    private string coverLetter = "";

    private void NextStep() => currentStep = Math.Min(currentStep + 1, 4);
    private void PreviousStep() => currentStep = Math.Max(currentStep - 1, 0);
    private void GoToStep(int step) => currentStep = step;

    private async Task<int> HandleSubmit()
    {
        var application = new JobApplication(
            new PersonalInfo(fullName, email, phone, address),
            new WorkHistory(workEntries.Select(e => new WorkEntry(
                e.Company, e.Title, e.StartDate, e.IsCurrent ? null : e.EndDate, e.Description
            )).ToList()),
            references.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList(),
            coverLetter
        );

        return await ApplicationService.SubmitApplicationAsync(application);
    }
}

namespace sv_e79b6c62dd1745f3a1c107394483f632.Models;

public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

namespace sv_e79b6c62dd1745f3a1c107394483f632.Services;

using sv_e79b6c62dd1745f3a1c107394483f632.Models;

public class ApplicationService : IApplicationService
{
    private static int _nextId = 1000;

    public async Task<int> SubmitApplicationAsync(JobApplication application)
    {
        await Task.Delay(1000); // Simulate network delay
        return Interlocked.Increment(ref _nextId);
    }

    public async Task<bool> ValidateEmailAsync(string email)
    {
        await Task.Delay(300); // Simulate validation
        return !string.IsNullOrWhiteSpace(email)
            && email.Contains('@')
            && email.Contains('.');
    }
}

@namespace sv_e79b6c62dd1745f3a1c107394483f632.Components.Pages.Apply

<nav aria-label="Application steps" class="mb-4">
    <ol class="step-indicator d-flex list-unstyled justify-content-between position-relative">
        @for (int i = 0; i < StepNames.Count; i++)
        {
            var stepIndex = i;
            var isCurrent = stepIndex == CurrentStep;
            var isCompleted = stepIndex < CurrentStep;
            var isFuture = stepIndex > CurrentStep;

            <li class="step-item text-center flex-fill @(isCurrent ? "active" : "") @(isCompleted ? "completed" : "") @(isFuture ? "future" : "")"
                @onclick="() => OnStepClick(stepIndex)"
                style="cursor: @(isCompleted ? "pointer" : "default")">
                <div class="step-circle mx-auto mb-1 d-flex align-items-center justify-content-center rounded-circle
                    @(isCurrent ? "bg-primary text-white" : isCompleted ? "bg-success text-white" : "bg-light text-muted border")"
                     style="width: 36px; height: 36px; font-size: 0.85rem;">
                    @if (isCompleted)
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        <span>@(stepIndex + 1)</span>
                    }
                </div>
                <small class="@(isCurrent ? "fw-bold text-primary" : isCompleted ? "text-success" : "text-muted")">
                    @StepNames[stepIndex]
                </small>
            </li>
        }
    </ol>
</nav>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public EventCallback<int> OnNavigateToStep { get; set; }

    private static readonly List<string> StepNames = new()
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };

    private async Task OnStepClick(int step)
    {
        if (step < CurrentStep)
        {
            await OnNavigateToStep.InvokeAsync(step);
        }
    }
}

