@rendermode InteractiveServer

@using sv_e79b6c62dd1745f3a1c107394483f632.Components.Pages.Apply
@using sv_e79b6c62dd1745f3a1c107394483f632.Models
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4 text-center">Job Application</h2>

    <StepIndicator CurrentStep="currentStep" OnNavigateToStep="GoToStep" />

    @switch (currentStep)
    {
        case 0:
            <PersonalInfoStep
                @bind-FullName="fullName"
                @bind-Email="email"
                @bind-Phone="phone"
                @bind-Address="address"
                ValidateEmail="ApplicationService.ValidateEmailAsync"
                OnNext="NextStep" />
            break;

        case 1:
            <WorkHistoryStep
                @bind-Entries="workEntries"
                OnNext="NextStep"
                OnBack="PreviousStep" />
            break;

        case 2:
            <ReferencesStep
                @bind-References="references"
                OnNext="NextStep"
                OnBack="PreviousStep" />
            break;

        case 3:
            <CoverLetterStep
                @bind-CoverLetter="coverLetter"
                OnNext="NextStep"
                OnBack="PreviousStep" />
            break;

        case 4:
            <ReviewStep
                FullName="@fullName"
                Email="@email"
                Phone="@phone"
                Address="@address"
                WorkEntries="workEntries"
                References="references"
                CoverLetter="@coverLetter"
                OnBack="PreviousStep"
                OnEditSection="GoToStep"
                SubmitApplication="HandleSubmit" />
            break;
    }
</div>

@code {
    private int currentStep = 0;

    // Step 1: Personal Info
    private string fullName = "";
    private string email = "";
    private string phone = "";
    private string address = "";

    // Step 2: Work History
    private List<WorkHistoryStep.WorkEntryModel> workEntries = new()
    {
        new WorkHistoryStep.WorkEntryModel()
    };

    // Step 3: References
    private List<ReferencesStep.ReferenceModel> references = new()
    {
        new ReferencesStep.ReferenceModel(),
        new ReferencesStep.ReferenceModel()
    };

    // Step 4: Cover Letter
    private string coverLetter = "";

    private void NextStep() => currentStep = Math.Min(currentStep + 1, 4);
    private void PreviousStep() => currentStep = Math.Max(currentStep - 1, 0);
    private void GoToStep(int step) => currentStep = step;

    private async Task<int> HandleSubmit()
    {
        var application = new JobApplication(
            new PersonalInfo(fullName, email, phone, address),
            new WorkHistory(workEntries.Select(e => new WorkEntry(
                e.Company, e.Title, e.StartDate, e.IsCurrent ? null : e.EndDate, e.Description
            )).ToList()),
            references.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList(),
            coverLetter
        );

        return await ApplicationService.SubmitApplicationAsync(application);
    }
}
