@namespace sv_e79b6c62dd1745f3a1c107394483f632.Components.Pages.Apply

<nav aria-label="Application steps" class="mb-4">
    <ol class="step-indicator d-flex list-unstyled justify-content-between position-relative">
        @for (int i = 0; i < StepNames.Count; i++)
        {
            var stepIndex = i;
            var isCurrent = stepIndex == CurrentStep;
            var isCompleted = stepIndex < CurrentStep;
            var isFuture = stepIndex > CurrentStep;

            <li class="step-item text-center flex-fill @(isCurrent ? "active" : "") @(isCompleted ? "completed" : "") @(isFuture ? "future" : "")"
                @onclick="() => OnStepClick(stepIndex)"
                style="cursor: @(isCompleted ? "pointer" : "default")">
                <div class="step-circle mx-auto mb-1 d-flex align-items-center justify-content-center rounded-circle
                    @(isCurrent ? "bg-primary text-white" : isCompleted ? "bg-success text-white" : "bg-light text-muted border")"
                     style="width: 36px; height: 36px; font-size: 0.85rem;">
                    @if (isCompleted)
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        <span>@(stepIndex + 1)</span>
                    }
                </div>
                <small class="@(isCurrent ? "fw-bold text-primary" : isCompleted ? "text-success" : "text-muted")">
                    @StepNames[stepIndex]
                </small>
            </li>
        }
    </ol>
</nav>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public EventCallback<int> OnNavigateToStep { get; set; }

    private static readonly List<string> StepNames = new()
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };

    private async Task OnStepClick(int step)
    {
        if (step < CurrentStep)
        {
            await OnNavigateToStep.InvokeAsync(step);
        }
    }
}

