@namespace sv_e79b6c62dd1745f3a1c107394483f632.Components.Pages.Apply

<h4 class="mb-3">Personal Information</h4>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

<div class="mb-3">
    <label class="form-label">Full Name <span class="text-danger">*</span></label>
    <input type="text" class="form-control" @bind="FullName" @bind:event="oninput" placeholder="John Doe" />
</div>

<div class="mb-3">
    <label class="form-label">Email <span class="text-danger">*</span></label>
    <input type="email" class="form-control" @bind="Email" @bind:event="oninput" placeholder="john@example.com" />
    @if (IsValidatingEmail)
    {
        <div class="form-text text-info">Validating email...</div>
    }
</div>

<div class="mb-3">
    <label class="form-label">Phone <span class="text-danger">*</span></label>
    <input type="tel" class="form-control" @bind="Phone" @bind:event="oninput" placeholder="(555) 123-4567" />
</div>

<div class="mb-3">
    <label class="form-label">Address <span class="text-danger">*</span></label>
    <textarea class="form-control" rows="2" @bind="Address" @bind:event="oninput" placeholder="123 Main St, City, State ZIP"></textarea>
</div>

<div class="d-flex justify-content-end">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidatingEmail">
        Next &raquo;
    </button>
</div>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public EventCallback<string> FullNameChanged { get; set; }
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public EventCallback<string> EmailChanged { get; set; }
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public EventCallback<string> PhoneChanged { get; set; }
    [Parameter] public string Address { get; set; } = "";
    [Parameter] public EventCallback<string> AddressChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public Func<string, Task<bool>> ValidateEmail { get; set; } = default!;

    private string? ErrorMessage;
    private bool IsValidatingEmail;

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (string.IsNullOrWhiteSpace(FullName))
        {
            ErrorMessage = "Full name is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(Email))
        {
            ErrorMessage = "Email is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(Phone))
        {
            ErrorMessage = "Phone number is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(Address))
        {
            ErrorMessage = "Address is required.";
            return;
        }

        // Sync bound values back to parent before validation
        await FullNameChanged.InvokeAsync(FullName);
        await EmailChanged.InvokeAsync(Email);
        await PhoneChanged.InvokeAsync(Phone);
        await AddressChanged.InvokeAsync(Address);

        IsValidatingEmail = true;
        try
        {
            var isValid = await ValidateEmail(Email);
            if (!isValid)
            {
                ErrorMessage = "The email address is not valid.";
                return;
            }
        }
        finally
        {
            IsValidatingEmail = false;
        }

        await OnNext.InvokeAsync();
    }
}

